import React, { useState, useEffect } from 'react';

function App() {
  const [services, setServices] = useState([]);
  const API_URL = "http://localhost:8081/api/services";

  useEffect(() => {
    fetch(API_URL).then(res => res.json()).then(data => setServices(data));
  }, []);

  const handleBooking = (serviceName) => {
    alert(`🎉 እናመሰግናለን! የ"${serviceName}" አገልግሎት ምዝገባዎ በተሳካ ሁኔታ ተጠናቋል። በቅርብ ሰዓት እንገናኛለን!`);
  };

  return (
      <div style={{ fontFamily: 'Segoe UI, sans-serif', padding: '40px', backgroundColor: '#f4f7f6', minHeight: '100vh' }}>
        <header style={{ textAlign: 'center', marginBottom: '40px' }}>
          <h1 style={{ color: '#2c3e50', fontSize: '2.5rem' }}>✨ የክላውድ ፈጣን የጽዳት አገልግሎት</h1>
          <p style={{ color: '#7f8c8d' }}>የሚፈልጉትን የጽዳት አይነት መርጠው በጥቂት ሰከንዶች ውስጥ ቦታ ያስይዙ</p>
        </header>

        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '25px', maxWidth: '1200px', margin: '0 auto' }}>
          {services.map(service => (
              <div key={service.id} style={{ backgroundColor: '#fff', borderRadius: '12px', padding: '25px', boxShadow: '0 4px 15px rgba(0,0,0,0.05)', textAlign: 'center', border: '1px solid #eef2f5' }}>
                <h3 style={{ color: '#2c3e50', margin: '10px 0' }}>{service.serviceName}</h3>
                <p style={{ fontSize: '1.8rem', fontWeight: 'bold', color: '#2ecc71', margin: '15px 0' }}>{service.price} ETB</p>
                <p style={{ color: '#95a5a6', fontSize: '0.9rem' }}>⏱️ የቆይታ ጊዜ: {service.duration}</p>
                <button
                    onClick={() => handleBooking(service.serviceName)}
                    disabled={!service.available}
                    style={{ width: '100%', padding: '12px', backgroundColor: service.available ? '#3498db' : '#bdc3c7', color: '#fff', border: 'none', borderRadius: '6px', fontSize: '1rem', fontWeight: 'bold', cursor: 'pointer', marginTop: '15px', transition: '0.3s' }}
                >
                  {service.available ? "አሁኑኑ እዘዝ (Book Now)" : "ለጊዜው አልተመቸም"}
                </button>
              </div>
          ))}
        </div>
      </div>
  );
}

export default App;
